// Product plugin targets generated by src/build/build.js.
//
// Paths are relative to source roots:
// - shared: src/shared/*
// - plugin: src/plugins/<name>/*
// - skills: src/skills/<skill>/*
//
// The build copies only files listed here. Keep this as an allowlist so product
// outputs cannot accidentally receive source specs, local notes, or metadata for
// another agent platform.
const pluginTargets = [
  {
    // Target name must match the output submodule directory and
    // plugin-versions.json key.
    name: "claude",
    // Human-readable agent product name exposed to EJS templates.
    agentName: "Claude Code",
    // Manifest path in the generated plugin root. build.js updates its version.
    manifest: ".claude-plugin/plugin.json",
    includes: {
      // Product-neutral files copied into the generated plugin root.
      shared: [
        "CONTRIBUTING.md",
        "SECURITY.md",
      ],
      // Claude-specific package files copied from src/plugins/claude.
      plugin: [
        ".claude-plugin/plugin.json",
        "README.md",
      ],
      // Files copied/rendered for every skill directory. Claude needs the
      // SKILL.md body only; Codex UI metadata is intentionally omitted.
      skills: [
        "SKILL.md.ejs",
      ],
    },
  },
  {
    // Target name must match the output submodule directory and
    // plugin-versions.json key.
    name: "codex",
    // Human-readable agent product name exposed to EJS templates.
    agentName: "Codex",
    // Manifest path in the generated plugin root. build.js updates its version.
    manifest: ".codex-plugin/plugin.json",
    includes: {
      // Product-neutral files copied into the generated plugin root.
      shared: [
        "CONTRIBUTING.md",
        "SECURITY.md",
        "assets/logo.svg",
      ],
      // Codex-specific package files copied from src/plugins/codex.
      plugin: [
        ".codex-plugin/plugin.json",
        "README.md",
      ],
      // Files copied/rendered for every skill directory. openai.yaml is Codex
      // UI metadata and should not be emitted for other products.
      skills: [
        "SKILL.md.ejs",
        "agents/openai.yaml",
      ],
    },
  },
];

module.exports = {
  pluginTargets,
};
